    public static function getOrderStateTypeByCode(string $orderStateCode) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_OrderStateType object');
        $query->leftJoin('object.orderStateTypeLangs orderStateTypeLangs WITH orderStateTypeLangs.Language_ID=1');
        $query->where('orderStateTypeLangs.Name=?', $orderStateCode);
        
        return $query->fetchOne();
    }

    /**
     * @return array
     */
    public static function getOrderStateTypes(): array {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_OrderStateType object');
        $query->leftJoin('object.orderStateTypeLangs orderStateTypeLangs');
        $query->andWhere('object.ID < 6');
        $orderStateTypes = $query->execute()->toArray();

        $output = [];

        foreach ( $orderStateTypes as $orderStateType ) {
            $outputItem = [];
            $outputItem['ID'] = $orderStateType['ID'];
            $outputItem['Name'] = $orderStateType['orderStateTypeLangs'][0]['Name'];

            $query = Doctrine_Query::create();
            $query->from('Admin_Model_Order object');
            $query->where('object.OrderStateType_ID = ?', $orderStateType['ID']);
            $outputItem['Count'] = $query->count();

            $output[] = $outputItem;
        }

        return $output;
    }
